def total_due(items, tax_rate):
    subtotal = 0.0
    discountable = 0.0
    for item in items:
        line = item["price"] * item.get("quantity", 1)
        subtotal += line
        if item.get("category") != "gift_card":
            discountable += line
    if subtotal > 100:
        subtotal -= discountable * 0.1
    return round(subtotal * (1 + tax_rate), 2)
